#include <stdio.h>
#define MAX_SIZE 1000

int stack[MAX_SIZE];
int top;

void push(int element) {
    if (top < MAX_SIZE - 1) {
        stack[++top] = element;
    }
}

int pop() {
    if (top >= 0) {
        return stack[top--];
    }
    return -1; // should never happen for valid input
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        top = -1; // reset stack for each test case
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            push(x);
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", pop());
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

