const fs = require('fs');
const input = fs.readFileSync(0, 'utf8').trim().split(/\s+/);
let idx = 0;
const T = parseInt(input[idx++], 10);
let outputs = [];
for (let t = 0; t < T; t++) {
    const N = parseInt(input[idx++], 10);
    const stack = [];
    for (let i = 0; i < N; i++) {
        stack.push(parseInt(input[idx++], 10));
    }
    const rev = [];
    for (let i = 0; i < N; i++) {
        rev.push(stack.pop());
    }
    outputs.push(rev.join(' '));
}
